  defaultAccount?: string;
  /** API key for authenticating with the PulseBoard service. */
  apiKey?: SecretInput;
  /** PulseBoard service endpoint URL. */
  serviceUrl?: string;
  /** PulseBoard username/handle for this account. */
  handle?: string;
  /** DM access policy: pairing, allowlist, open, or disabled. */
  dmPolicy?: PulseBoardDmPolicy;
  /** Allowed sender handles for DMs. */
  allowFrom?: Array<string | number>;
  /** Group (board) access policy: allowlist, open, or disabled. */
  groupPolicy?: PulseBoardGroupPolicy;
  /** Allowed sender handles for board messages. */
  groupAllowFrom?: Array<string | number>;
  /** Named board configurations. */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** Boards to auto-join on startup. */
  joinBoards?: string[];
}

/**
 * Fully resolved account state at runtime.
 */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiKey: string;
  serviceUrl: string;
  handle: string;
  joinBoards: string[];
  config: PulseBoardAccountConfig;
}

/** Default PulseBoard service endpoint. */
const DEFAULT_SERVICE_URL = "https://api.pulseboard.example/v1";

function resolveConfiguredDefaultPulseBoardAccountId(
  cfg: OpenClawConfig,
): string | undefined {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

/**
 * List all configured PulseBoard account IDs.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/**
 * Get the default account ID.
 */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;

  const baseEnabled = pbCfg?.enabled !== false;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey) ?? "";
  const handle = pbCfg?.handle?.trim() ?? "";
  const configured = Boolean(apiKey) && Boolean(handle);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    apiKey,
    serviceUrl: pbCfg?.serviceUrl?.trim() || DEFAULT_SERVICE_URL,
    handle,
    joinBoards: pbCfg?.joinBoards ?? [],
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      serviceUrl: pbCfg?.serviceUrl,
      handle: pbCfg?.handle,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      groupPolicy: pbCfg?.groupPolicy,
      groupAllowFrom: pbCfg?.groupAllowFrom,
      boards: pbCfg?.boards,
      joinBoards: pbCfg?.joinBoards,
    },
  };
}

/**
 * Normalize a PulseBoard handle to lowercase, stripped of leading @.
 */
export function normalizePulseBoardHandle(raw: string): string {
  return raw.trim().replace(/^@/, "").toLowerCase();
}

