import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Per-board configuration schema.
 */
const PulseBoardBoardSchema = z
  .object({
    enabled: z.boolean().optional(),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

/**
 * Group policy: how board messages are handled.
 */
const PulseBoardGroupPolicySchema = z
  .enum(["allowlist", "open", "disabled"])
  .optional();

/**
 * Zod schema for channels.pulseboard.* configuration.
 */
export const PulseBoardConfigSchema = z.object({
  /** Account name (optional display name). */
  name: z.string().optional(),

  /** Optional default account id for routing/account selection. */
  defaultAccount: z.string().optional(),

  /** Whether this channel is enabled. */
  enabled: z.boolean().optional(),

  /** Markdown formatting overrides (tables). */
  markdown: MarkdownConfigSchema,

  /** API key for authenticating with the PulseBoard service. */
  apiKey: buildSecretInputSchema().optional(),

  /** PulseBoard service endpoint URL (defaults to public API). */
  serviceUrl: z.string().url().optional(),

  /** PulseBoard username/handle for this account. */
  handle: z.string().optional(),

  /** DM access policy: pairing, allowlist, open, or disabled. */
  dmPolicy: DmPolicySchema.optional(),

  /** Allowed sender handles for DMs (handle or * for any). */
  allowFrom: AllowFromListSchema,

  /** Group (board) access policy: allowlist, open, or disabled. */
  groupPolicy: PulseBoardGroupPolicySchema,

  /** Allowed sender handles for board messages. */
  groupAllowFrom: z.array(z.union([z.string(), z.number()])).optional(),

  /** Per-board configuration overrides keyed by board name. */
  boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),

  /** Boards to auto-join on gateway startup. */
  joinBoards: z.array(z.string()).optional(),
});

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/**
 * JSON Schema for Control UI (converted from Zod).
 */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

